#include<cstdio>
#include<cstring> 
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10,GN=N<<1,GM=N<<1,SN=N<<1;
struct Graph
{
	int head[GN],des[GM],nxt[GM],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[cnt]=y;head[x]=cnt;}
}a;
int ch[SN][26],len[SN],fa[SN],siz[SN],lst=1,cnt=1;
inline void ins(int c)
{
	int p=lst,np=lst=++cnt;siz[np]=1;
	for(;p&&!ch[p][c];p=fa[p])ch[p][c]=np;
	if(!p){fa[np]=1;}
	else
	{
		int v=ch[p][c];
		if(len[v]==len[p]+1){fa[np]=v;}
		else
		{
			int nv=++cnt;
			fa[nv]=fa[v];len[nv]=len[p]+1;
			memcpy(ch[nv],ch[v],sizeof(ch[v]));
			for(;p&&ch[p][c]==v;p=fa[p])ch[p][c]=nv;
			fa[v]=fa[np]=nv;
		}
	}
}
inline void Getsiz(int u=1){grep(a,u,i){Getsiz(a.des[i]);siz[u]+=siz[a.des[i]];}}
int stk[SN],top;
char s[N],s1[N];bool vis[SN];
inline void Match()
{
	scanf("%s",s);int L=strlen(s);
	int p=1,cur=0;rep(0,L-1,i)
	{
		int c=s[i]-'a';
		while(p^1&&!ch[p][c])cur=len[p=fa[p]];
		ch[p][c]?(p=ch[p][c],++cur):0;
	}
	long long ans=0;rep(0,L-1,i)
	{
		int c=s[i]-'a';
		if(cur==L)
		{
			if(!vis[p])
			{
				ans+=siz[p];
				vis[stk[++top]=p]=1;
//				printf("qwq : %d\n",p);
			}
			if((--cur)==len[fa[p]])p=fa[p];
		}
		while(p^1&&!ch[p][c])cur=len[p=fa[p]];
		ch[p][c]?(p=ch[p][c],++cur):0;
	}
	while(top)vis[stk[top--]]=0;	
	printf("%lld\n",ans);
}
inline void Solve()
{
	scanf("%s",s1);int n=strlen(s1);
	rep(0,n-1,i)ins(s1[i]-'a');
	rep(2,cnt,i)a.ins(fa[i],i);Getsiz();
	int m=read();while(m--)Match();return;
}
int main(){Solve();return 0;}
